import{_ as t,c as o,o as a,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"OpenCode Plugin Installation | Plannotator","description":"Learn how to install the Plannotator plugin in OpenCode. Configure opencode.json, run installation script to get slash commands, set up environment variables for remote mode, and verify plugin is working.","frontmatter":{"title":"OpenCode Plugin Installation | Plannotator","sidebarTitle":"OpenCode Install","subtitle":"Install the OpenCode Plugin","description":"Learn how to install the Plannotator plugin in OpenCode. Configure opencode.json, run installation script to get slash commands, set up environment variables for remote mode, and verify plugin is working.","tags":["Installation","Configuration","OpenCode"],"prerequisite":["start-getting-started"],"order":3},"headers":[],"relativePath":"backnotprop/plannotator/start/installation-opencode/index.md","filePath":"backnotprop/plannotator/start/installation-opencode/index.md"}'),i={name:"backnotprop/plannotator/start/installation-opencode/index.md"};function s(l,e,r,d,p,c){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="install-the-opencode-plugin" tabindex="-1">Install the OpenCode Plugin <a class="header-anchor" href="#install-the-opencode-plugin" aria-label="Permalink to &quot;Install the OpenCode Plugin&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Install the Plannotator plugin in OpenCode</li><li>Configure the <code>submit_plan</code> tool and <code>/plannotator-review</code> command</li><li>Set up environment variables (remote mode, port, browser, etc.)</li><li>Verify that the plugin installation was successful</li></ul><h2 id="your-current-struggle" tabindex="-1">Your Current Struggle <a class="header-anchor" href="#your-current-struggle" aria-label="Permalink to &quot;Your Current Struggle&quot;">​</a></h2><p>When using AI Agent in OpenCode, plan reviews require reading plain text in the terminal, making precise feedback difficult. You want a visual interface to annotate plans, add comments, and automatically send structured feedback back to the Agent.</p><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><p><strong>Required before using Plannotator</strong>: If you&#39;re developing in the OpenCode environment and want an interactive plan review experience.</p><h2 id="🎒-before-you-start" tabindex="-1">🎒 Before You Start <a class="header-anchor" href="#🎒-before-you-start" aria-label="Permalink to &quot;🎒 Before You Start&quot;">​</a></h2><ul><li>[ ] <a href="https://opencode.ai/" target="_blank" rel="noreferrer">OpenCode</a> installed</li><li>[ ] Basic understanding of <code>opencode.json</code> configuration (OpenCode plugin system)</li></ul><div class="warning custom-block"><p class="custom-block-title">Prerequisites</p><p>If you&#39;re unfamiliar with OpenCode basics, we recommend reading the <a href="https://opencode.ai/docs" target="_blank" rel="noreferrer">OpenCode official documentation</a> first.</p></div><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><p>Plannotator provides two core features for OpenCode:</p><ol><li><strong><code>submit_plan</code> tool</strong> - Called when Agent completes the plan, opens browser for interactive review</li><li><strong><code>/plannotator-review</code> command</strong> - Manually triggers Git diff code review</li></ol><p>Installation involves two steps:</p><ol><li>Add plugin configuration in <code>opencode.json</code> (enable <code>submit_plan</code> tool)</li><li>Run installation script (get <code>/plannotator-review</code> command)</li></ol><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-install-plugin-via-opencode-json" tabindex="-1">Step 1: Install Plugin via opencode.json <a class="header-anchor" href="#step-1-install-plugin-via-opencode-json" aria-label="Permalink to &quot;Step 1: Install Plugin via opencode.json&quot;">​</a></h3><p>Find your OpenCode configuration file (usually in project root or user config directory), add Plannotator to the <code>plugin</code> array:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://opencode.ai/config.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@plannotator/opencode@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Why</strong><code>opencode.json</code> is OpenCode&#39;s plugin configuration file. After adding the plugin name, OpenCode will automatically download and load the plugin from the npm registry.</p><p>What you should see: OpenCode will display a message &quot;Loading plugin: @plannotator/opencode...&quot; on startup.</p><hr><h3 id="step-2-restart-opencode" tabindex="-1">Step 2: Restart OpenCode <a class="header-anchor" href="#step-2-restart-opencode" aria-label="Permalink to &quot;Step 2: Restart OpenCode&quot;">​</a></h3><p><strong>Why</strong> Plugin configuration changes require a restart to take effect.</p><p>What you should see: OpenCode reloads all plugins.</p><hr><h3 id="step-3-run-installation-script-to-get-slash-commands" tabindex="-1">Step 3: Run Installation Script to Get Slash Commands <a class="header-anchor" href="#step-3-run-installation-script-to-get-slash-commands" aria-label="Permalink to &quot;Step 3: Run Installation Script to Get Slash Commands&quot;">​</a></h3><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-kmX6e" id="tab-lGXxoJf" checked><label data-title="macOS / Linux / WSL" for="tab-lGXxoJf">macOS / Linux / WSL</label><input type="radio" name="group-kmX6e" id="tab-smnkOqj"><label data-title="Windows PowerShell" for="tab-smnkOqj">Windows PowerShell</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://plannotator.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plannotator.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div></div></div><p><strong>Why</strong> This script will:</p><ol><li>Download the <code>plannotator</code> CLI tool to your system</li><li>Install the <code>/plannotator-review</code> slash command to OpenCode</li><li>Clear any cached plugin versions</li></ol><p>What you should see: Installation success message, like &quot;Plannotator installed successfully!&quot;</p><hr><h3 id="step-4-verify-installation" tabindex="-1">Step 4: Verify Installation <a class="header-anchor" href="#step-4-verify-installation" aria-label="Permalink to &quot;Step 4: Verify Installation&quot;">​</a></h3><p>Check if the plugin works properly in OpenCode:</p><p><strong>Check if <code>submit_plan</code> tool is available</strong>:</p><ul><li>Ask Agent &quot;Please use submit_plan to submit plan&quot; in conversation</li><li>If plugin is working, Agent should be able to see and call this tool</li></ul><p><strong>Check if <code>/plannotator-review</code> command is available</strong>:</p><ul><li>Type <code>/plannotator-review</code> in the input box</li><li>If plugin is working, you should see command suggestions</li></ul><p>What you should see: Both features work normally without error messages.</p><hr><h3 id="step-5-configure-environment-variables-optional" tabindex="-1">Step 5: Configure Environment Variables (Optional) <a class="header-anchor" href="#step-5-configure-environment-variables-optional" aria-label="Permalink to &quot;Step 5: Configure Environment Variables (Optional)&quot;">​</a></h3><p>Plannotator supports the following environment variables, configure according to your needs:</p><details class="details custom-block"><summary>Environment Variable Reference</summary><table tabindex="0"><thead><tr><th>Environment Variable</th><th>Purpose</th><th>Default</th><th>Example</th></tr></thead><tbody><tr><td><code>PLANNOTATOR_REMOTE</code></td><td>Enable remote mode (devcontainer/SSH)</td><td>Not set</td><td><code>export PLANNOTATOR_REMOTE=1</code></td></tr><tr><td><code>PLANNOTATOR_PORT</code></td><td>Fixed port (required for remote mode)</td><td>Random local, 19432 remote</td><td><code>export PLANNOTATOR_PORT=9999</code></td></tr><tr><td><code>PLANNOTATOR_BROWSER</code></td><td>Custom browser path</td><td>System default</td><td><code>export PLANNOTATOR_BROWSER=&quot;/Applications/Google Chrome.app&quot;</code></td></tr><tr><td><code>PLANNOTATOR_SHARE</code></td><td>Disable URL sharing</td><td>Enabled</td><td><code>export PLANNOTATOR_SHARE=disabled</code></td></tr></tbody></table></details><p><strong>Remote mode configuration example</strong> (devcontainer/SSH):</p><p>In <code>.devcontainer/devcontainer.json</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;containerEnv&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;PLANNOTATOR_REMOTE&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;PLANNOTATOR_PORT&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;9999&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;forwardPorts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">9999</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Why</strong></p><ul><li>Remote mode: When running OpenCode in a container or remote machine, use a fixed port and automatically open browser</li><li>Port forwarding: Allow host machine to access services inside the container</li></ul><p>What you should see: When Agent calls <code>submit_plan</code>, console will display the server URL (instead of automatically opening browser), for example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plannotator server running at http://localhost:9999</span></span></code></pre></div><hr><h3 id="step-6-restart-opencode-if-environment-variables-were-modified" tabindex="-1">Step 6: Restart OpenCode (if environment variables were modified) <a class="header-anchor" href="#step-6-restart-opencode-if-environment-variables-were-modified" aria-label="Permalink to &quot;Step 6: Restart OpenCode (if environment variables were modified)&quot;">​</a></h3><p>If you configured environment variables in Step 5, restart OpenCode again for the configuration to take effect.</p><hr><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>After installation, confirm the following:</p><ul><li>[ ] <code>@plannotator/opencode@latest</code> added to <code>opencode.json</code></li><li>[ ] No plugin loading errors after OpenCode restart</li><li>[ ] Command suggestions appear when typing <code>/plannotator-review</code></li><li>[ ] (Optional) Environment variables configured correctly</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="common-error-1-plugin-loading-failure" tabindex="-1">Common Error 1: Plugin Loading Failure <a class="header-anchor" href="#common-error-1-plugin-loading-failure" aria-label="Permalink to &quot;Common Error 1: Plugin Loading Failure&quot;">​</a></h3><p><strong>Symptom</strong>: OpenCode prompts &quot;Failed to load plugin @plannotator/opencode&quot; on startup</p><p><strong>Possible Causes</strong>:</p><ul><li>Network issue prevents download from npm</li><li>npm cache corruption</li></ul><p><strong>Solution</strong>:</p><ol><li>Check network connection</li><li>Run installation script (it will clear plugin cache)</li><li>Manually clear npm cache: <code>npm cache clean --force</code></li></ol><hr><h3 id="common-error-2-slash-command-not-available" tabindex="-1">Common Error 2: Slash Command Not Available <a class="header-anchor" href="#common-error-2-slash-command-not-available" aria-label="Permalink to &quot;Common Error 2: Slash Command Not Available&quot;">​</a></h3><p><strong>Symptom</strong>: No command suggestions when typing <code>/plannotator-review</code></p><p><strong>Possible Cause</strong>: Installation script did not run successfully</p><p><strong>Solution</strong>: Re-run installation script (Step 3)</p><hr><h3 id="common-error-3-browser-won-t-open-in-remote-mode" tabindex="-1">Common Error 3: Browser Won&#39;t Open in Remote Mode <a class="header-anchor" href="#common-error-3-browser-won-t-open-in-remote-mode" aria-label="Permalink to &quot;Common Error 3: Browser Won&#39;t Open in Remote Mode&quot;">​</a></h3><p><strong>Symptom</strong>: Browser doesn&#39;t open when calling <code>submit_plan</code> in devcontainer</p><p><strong>Possible Causes</strong>:</p><ul><li><code>PLANNOTATOR_REMOTE=1</code> not set</li><li>Port forwarding not configured</li></ul><p><strong>Solution</strong>:</p><ol><li>Confirm <code>PLANNOTATOR_REMOTE=1</code> is set</li><li>Check that <code>forwardPorts</code> in <code>.devcontainer/devcontainer.json</code> includes your configured port</li><li>Manually access the displayed URL: <code>http://localhost:9999</code></li></ol><hr><h3 id="common-error-4-port-conflict" tabindex="-1">Common Error 4: Port Conflict <a class="header-anchor" href="#common-error-4-port-conflict" aria-label="Permalink to &quot;Common Error 4: Port Conflict&quot;">​</a></h3><p><strong>Symptom</strong>: Server fails to start, prompts &quot;Port already in use&quot;</p><p><strong>Possible Cause</strong>: Previous server didn&#39;t close properly</p><p><strong>Solution</strong>:</p><ol><li>Change <code>PLANNOTATOR_PORT</code> to another port</li><li>Or manually kill the process occupying the port (macOS/Linux: <code>lsof -ti:9999 | xargs kill</code>)</li></ol><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>This lesson covered how to install and configure the Plannotator plugin in OpenCode:</p><ol><li><strong>Add plugin via <code>opencode.json</code></strong> - Enable <code>submit_plan</code> tool</li><li><strong>Run installation script</strong> - Get <code>/plannotator-review</code> slash command</li><li><strong>Configure environment variables</strong> - Adapt to remote mode and custom requirements</li><li><strong>Verify installation</strong> - Confirm plugin works properly</li></ol><p>After installation, you can:</p><ul><li>Let Agent use <code>submit_plan</code> to submit plans for interactive review</li><li>Use <code>/plannotator-review</code> to manually review Git diffs</li></ul><h2 id="next-up" tabindex="-1">Next Up <a class="header-anchor" href="#next-up" aria-label="Permalink to &quot;Next Up&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../../platforms/plan-review-basics/">Plan Review Basics</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to view AI-generated plans</li><li>Add different types of annotations (delete, replace, insert, comment)</li><li>Approve or reject plans</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Number</th></tr></thead><tbody><tr><td>Plugin entry definition</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></td><td>34-280</td></tr><tr><td><code>submit_plan</code> tool definition</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></td><td>209-252</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Plugin configuration (opencode.json) injection</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></td><td>55-63</td></tr><tr><td>Environment variable reading</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></td><td>37-51</td></tr><tr><td>Plan review server startup</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>Full file</td></tr><tr><td>Code review server startup</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></td><td>Full file</td></tr><tr><td>Remote mode detection</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/remote.ts" target="_blank" rel="noreferrer"><code>packages/server/remote.ts</code></a></td><td>Full file</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>PLANNOTATOR_REMOTE</code>: Remote mode flag (set to &quot;1&quot; or &quot;true&quot; to enable)</li><li><code>PLANNOTATOR_PORT</code>: Fixed port number (default random locally, 19432 remote by default)</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>startPlannotatorServer()</code>: Start plan review server</li><li><code>startReviewServer()</code>: Start code review server</li><li><code>getSharingEnabled()</code>: Get URL sharing toggle status (from OpenCode config or environment variable)</li></ul></details>`,93)])])}const g=t(i,[["render",s]]);export{u as __pageData,g as default};
